--
-- Table structure for table `crawl_task`
--

DROP TABLE IF EXISTS `crawl_task`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `crawl_task` (
  `task_id` int NOT NULL AUTO_INCREMENT COMMENT '任务ID',
  `task_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务名称',
  `data_source` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'meituan' COMMENT '数据源',
  `task_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'full' COMMENT '任务类型（full全量/incremental增量）',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending' COMMENT '状态（pending/running/success/failed）',
  `total_count` int DEFAULT '0' COMMENT '累计采集数量',
  `success_rate` decimal(5,2) DEFAULT NULL COMMENT '采集成功率（%）',
  `error_msg` text COLLATE utf8mb4_unicode_ci COMMENT '错误信息',
  `start_time` datetime DEFAULT NULL COMMENT '开始时间',
  `end_time` datetime DEFAULT NULL COMMENT '结束时间',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`task_id`),
  KEY `idx_status` (`status`),
  KEY `idx_data_source` (`data_source`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='爬虫任务表';
/*!40101 SET character_set_client = @saved_cs_client */;

