--
-- Table structure for table `restaurant_info`
--

DROP TABLE IF EXISTS `restaurant_info`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `restaurant_info` (
  `restaurant_id` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '餐厅唯一标识（美团ID或UUID）',
  `restaurant_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '餐厅名称',
  `address` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '餐厅地址',
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '联系电话（已脱敏，如138****1234）',
  `business_hours` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '营业时间',
  `avg_price` decimal(10,2) DEFAULT '0.00' COMMENT '人均消费（元）',
  `rating_overall` decimal(3,1) DEFAULT '0.0' COMMENT '综合评分（1-5）',
  `review_count` int DEFAULT '0' COMMENT '评论总数',
  `cuisine_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '菜系类型',
  `district` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所属行政区（如浦东新区）',
  `business_area` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所属商圈（如陆家嘴）',
  `latitude` decimal(10,6) DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(10,6) DEFAULT NULL COMMENT '经度',
  `subway_distance` int DEFAULT NULL COMMENT '最近地铁距离（米）',
  `data_source` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'meituan' COMMENT '数据来源',
  `crawl_time` datetime DEFAULT NULL COMMENT '采集时间',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`restaurant_id`),
  KEY `idx_district` (`district`),
  KEY `idx_cuisine` (`cuisine_type`),
  KEY `idx_business_area` (`business_area`),
  KEY `idx_avg_price` (`avg_price`),
  KEY `idx_rating` (`rating_overall`),
  KEY `idx_latlng` (`latitude`,`longitude`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='餐厅基础信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

