--
-- Table structure for table `restaurant_review`
--

DROP TABLE IF EXISTS `restaurant_review`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `restaurant_review` (
  `review_id` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '评论唯一标识',
  `restaurant_id` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '关联餐厅ID',
  `user_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '用户ID（已脱敏）',
  `rating_overall` decimal(3,1) DEFAULT NULL COMMENT '综合评分（1-5）',
  `rating_taste` decimal(3,1) DEFAULT NULL COMMENT '口味评分',
  `rating_environment` decimal(3,1) DEFAULT NULL COMMENT '环境评分',
  `rating_service` decimal(3,1) DEFAULT NULL COMMENT '服务评分',
  `review_content` text COLLATE utf8mb4_unicode_ci COMMENT '评论内容',
  `review_time` datetime DEFAULT NULL COMMENT '评论时间',
  `like_count` int DEFAULT '0' COMMENT '点赞数',
  `sentiment_score` decimal(3,2) DEFAULT NULL COMMENT '情感得分（-1到1，正数为正面）',
  `data_source` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'meituan' COMMENT '数据来源',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`review_id`),
  KEY `idx_restaurant_id` (`restaurant_id`),
  KEY `idx_review_time` (`review_time`),
  CONSTRAINT `fk_review_restaurant` FOREIGN KEY (`restaurant_id`) REFERENCES `restaurant_info` (`restaurant_id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='评分评论表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `restaurant_review`
--

LOCK TABLES `restaurant_review` WRITE;
